  int64_t N, S;

  cin >> N >> S;

  vector<int64_t> vec(N);

  for(int i=0; i<N; i++){

    cin >> vec[i];

  }

  for(int i=0; i<N; i++){

    int64_t x = vec[i];

    dp[i+1][x] = powmod(2,N-1);

    for(int j=0; j<N_MAX; j++){

      dp[i+1][j] += dp[i][j]; //加えない

      if(j + x < N_MAX){ //加える

        int64_t y = dp[i][j];

        y %= MOD;

        y = y*modinv((int64_t)2,MOD) %MOD;

        dp[i+1][j+x] += y;

        dp[i+1][j+x] %= MOD;

      }

      dp[i+1][j] %= MOD;

    }

  }

